// frontend/src/pages/Users.js
import { useEffect, useMemo, useState } from "react";
import api from "../api";
import { toast } from "react-toastify";

/** ====== Config ====== **/
const PAGE_SIZE = 10;

/** Chuẩn hoá Page<?> trả từ Spring (Page hoặc mảng) */
function normalizePage(d) {
    if (Array.isArray(d)) return { list: d, pages: 1, totalElements: d.length };
    return {
        list: d?.content || [],
        pages: typeof d?.totalPages === "number" ? d.totalPages : 1,
        totalElements: typeof d?.totalElements === "number" ? d.totalElements : (d?.content?.length || 0),
    };
}

/** Lấy message lỗi từ backend để hiện rõ ràng */
function extractMsg(err) {
    return err?.response?.data?.message || err?.message || "Thao tác thất bại";
}

export default function UsersPage() {
    const [rows, setRows] = useState([]);
    const [page, setPage] = useState(0);
    const [totalPages, setTotalPages] = useState(1);
    const [totalElements, setTotalElements] = useState(0);

    const [roles, setRoles] = useState([]); // /api/roles trả về {id,name,userCount}
    const [editing, setEditing] = useState(null); // object user đang sửa

    // (Tuỳ chọn) Tìm kiếm nhanh theo từ khoá
    const [q, setQ] = useState("");

    /** ====== Loaders ====== **/
    const loadUsers = async (p = 0) => {
        const params = { page: p, size: PAGE_SIZE };
        if (q && q.trim()) params.q = q.trim(); // nếu BE đã hỗ trợ tham số q
        const res = await api.get("/api/users", { params });
        const n = normalizePage(res.data);
        setRows(n.list);
        setTotalPages(n.pages);
        setTotalElements(n.totalElements);
        setPage(p);
    };

    const loadRoles = async () => {
        const res = await api.get("/api/roles");
        setRoles(res.data || []);
    };

    useEffect(() => {
        loadUsers(0);
        loadRoles();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, []);

    /** ====== Helpers ====== **/
    const roleOptions = useMemo(() => roles.map(r => ({ value: r.id, label: r.name })), [roles]);

    const openEdit = (u) => {
        setEditing({
            id: u.id,
            username: u.username || "",
            fullName: u.fullName || "",
            email: u.email || "",
            phone: u.phone || "",
            status: u.status || "ACTIVE",         // ACTIVE | INACTIVE
            roleId: u.roleId || null,             // id vai trò
            setPassword: false,                   // chỉ đặt true khi muốn đổi mật khẩu
            newPassword: "",
        });
    };

    const closeEdit = () => setEditing(null);

    /** ====== Actions ====== **/
    const onSave = async () => {
        const f = editing;
        if (!f) return;

        const payload = {
            username: (f.username || "").trim(),
            fullName: (f.fullName || "").trim(),
            email: (f.email || "").trim(),
            phone: (f.phone || "").trim(),
            status: f.status,
            roleId: f.roleId,
            setNewPassword: !!f.setPassword,
            newPassword: f.setPassword ? f.newPassword : null,
        };

        try {
            await api.put(`/api/users/${f.id}`, payload);
            toast.success("Đã lưu người dùng");
            closeEdit();
            loadUsers(page);
        } catch (err) {
            toast.error(extractMsg(err));
        }
    };

    const onSearch = async (e) => {
        e?.preventDefault?.();
        await loadUsers(0);
    };

    /** ====== UI ====== **/
    return (
        <div className="p-4">
            <div className="mb-3 flex items-center justify-between">
                <h2 className="text-xl font-semibold">Người dùng &amp; Phân quyền</h2>
                <form className="flex items-center gap-2" onSubmit={onSearch}>
                    <input
                        className="border rounded px-3 py-2 w-64"
                        placeholder="Tìm theo tên, email..."
                        value={q}
                        onChange={(e) => setQ(e.target.value)}
                    />
                    <button
                        type="submit"
                        className="px-3 py-2 rounded bg-indigo-600 text-white"
                    >
                        Tìm
                    </button>
                </form>
            </div>

            <div className="mb-2 text-sm text-gray-600">
                Tổng: <b>{totalElements}</b> người dùng
            </div>

            <div className="overflow-auto border rounded">
                <table className="min-w-full">
                    <thead>
                    <tr className="bg-gray-50 text-left">
                        <th className="p-2 border">Tên đăng nhập</th>
                        <th className="p-2 border">Họ tên</th>
                        <th className="p-2 border">Email</th>
                        <th className="p-2 border">Điện thoại</th>
                        <th className="p-2 border">Vai trò</th>
                        <th className="p-2 border">Trạng thái</th>
                        <th className="p-2 border">Thao tác</th>
                    </tr>
                    </thead>
                    <tbody>
                    {rows.length === 0 && (
                        <tr>
                            <td className="p-4 text-center text-gray-500" colSpan={7}>
                                Không có dữ liệu
                            </td>
                        </tr>
                    )}
                    {rows.map((u) => (
                        <tr key={u.id} className="border-t">
                            <td className="p-2 border">{u.username}</td>
                            <td className="p-2 border">{u.fullName}</td>
                            <td className="p-2 border">{u.email}</td>
                            <td className="p-2 border">{u.phone}</td>
                            <td className="p-2 border">{u.roleName || u.role?.name || "-"}</td>
                            <td className="p-2 border">
                  <span
                      className={
                          "inline-flex items-center px-2 py-0.5 rounded text-xs " +
                          (String(u.status).toUpperCase() === "ACTIVE"
                              ? "bg-green-100 text-green-700"
                              : "bg-gray-100 text-gray-600")
                      }
                  >
                    {u.status}
                  </span>
                            </td>
                            <td className="p-2 border">
                                <button
                                    className="px-2 py-1 text-blue-600 hover:underline"
                                    onClick={() => openEdit(u)}
                                >
                                    Sửa
                                </button>
                            </td>
                        </tr>
                    ))}
                    </tbody>
                </table>
            </div>

            {/* Pagination */}
            <div className="flex items-center justify-between mt-3">
                <div className="text-sm text-gray-600">
                    Trang {page + 1}/{totalPages}
                </div>
                <div className="flex gap-2">
                    <button
                        className="px-3 py-1 border rounded disabled:opacity-50"
                        disabled={page <= 0}
                        onClick={() => loadUsers(page - 1)}
                    >
                        ← Trước
                    </button>
                    <button
                        className="px-3 py-1 border rounded disabled:opacity-50"
                        disabled={page + 1 >= totalPages}
                        onClick={() => loadUsers(page + 1)}
                    >
                        Sau →
                    </button>
                </div>
            </div>

            {/* Edit Modal */}
            {editing && (
                <div className="fixed inset-0 bg-black/30 flex items-center justify-center z-50">
                    <div className="bg-white rounded-lg w-[760px] p-5 shadow-xl">
                        <div className="text-lg font-semibold mb-4">Sửa người dùng</div>

                        <div className="grid grid-cols-2 gap-4">
                            <label className="flex flex-col gap-1">
                                <span className="text-sm">Tên đăng nhập</span>
                                <input
                                    className="border rounded px-3 py-2"
                                    value={editing.username}
                                    onChange={(e) =>
                                        setEditing((s) => ({ ...s, username: e.target.value }))
                                    }
                                />
                            </label>

                            <label className="flex flex-col gap-1">
                                <span className="text-sm">Họ tên</span>
                                <input
                                    className="border rounded px-3 py-2"
                                    value={editing.fullName}
                                    onChange={(e) =>
                                        setEditing((s) => ({ ...s, fullName: e.target.value }))
                                    }
                                />
                            </label>

                            <label className="flex flex-col gap-1">
                                <span className="text-sm">Email</span>
                                <input
                                    className="border rounded px-3 py-2"
                                    value={editing.email}
                                    onChange={(e) =>
                                        setEditing((s) => ({ ...s, email: e.target.value }))
                                    }
                                />
                            </label>

                            <label className="flex flex-col gap-1">
                                <span className="text-sm">Điện thoại</span>
                                <input
                                    className="border rounded px-3 py-2"
                                    value={editing.phone}
                                    onChange={(e) =>
                                        setEditing((s) => ({ ...s, phone: e.target.value }))
                                    }
                                />
                            </label>

                            <label className="flex flex-col gap-1">
                                <span className="text-sm">Vai trò</span>
                                <select
                                    className="border rounded px-3 py-2"
                                    value={editing.roleId || ""}
                                    onChange={(e) =>
                                        setEditing((s) => ({
                                            ...s,
                                            roleId: e.target.value ? Number(e.target.value) : null,
                                        }))
                                    }
                                >
                                    <option value="" disabled>
                                        Chọn vai trò...
                                    </option>
                                    {roleOptions.map((r) => (
                                        <option key={r.value} value={r.value}>
                                            {r.label}
                                        </option>
                                    ))}
                                </select>
                            </label>

                            <label className="flex flex-col gap-1">
                                <span className="text-sm">Trạng thái</span>
                                <select
                                    className="border rounded px-3 py-2"
                                    value={editing.status}
                                    onChange={(e) =>
                                        setEditing((s) => ({ ...s, status: e.target.value }))
                                    }
                                >
                                    <option value="ACTIVE">ACTIVE</option>
                                    <option value="INACTIVE">INACTIVE</option>
                                </select>
                            </label>

                            <label className="col-span-2 inline-flex items-center gap-2 mt-1">
                                <input
                                    type="checkbox"
                                    checked={!!editing.setPassword}
                                    onChange={(e) =>
                                        setEditing((s) => ({ ...s, setPassword: e.target.checked }))
                                    }
                                />
                                <span>Đặt mật khẩu mới</span>
                            </label>

                            {editing.setPassword && (
                                <label className="col-span-2 flex flex-col gap-1">
                                    <span className="text-sm">Mật khẩu mới</span>
                                    <input
                                        type="password"
                                        className="border rounded px-3 py-2"
                                        value={editing.newPassword}
                                        onChange={(e) =>
                                            setEditing((s) => ({ ...s, newPassword: e.target.value }))
                                        }
                                    />
                                </label>
                            )}
                        </div>

                        <div className="flex justify-end gap-2 mt-5">
                            <button className="px-3 py-2" onClick={closeEdit}>
                                Hủy
                            </button>
                            <button
                                className="px-3 py-2 rounded bg-indigo-600 text-white"
                                onClick={onSave}
                            >
                                Lưu
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}
